date.type:
{
		/**
		 * @description Whether to display the date part.
		 * When true, the date component will be included in the formatted output.
		 */
		display: boolean;

		/**
		 * @description Format specification for the date.
		 * Can be a set of specific date parts to include (days, months, years) or 'week' for week-based formatting.
		 * @hidden
		 */
		format?: Set<DateParts> | 'week';
	}

time.type:
{
		/**
		 * @description Whether to display the time part.
		 * When true, the time component will be included in the formatted output.
		 */
		display: boolean;

		/**
		 * @description Format specification for the time.
		 * Can be a set of specific time parts to include (hours, minutes, seconds) or 'hour' for hour-only formatting.
		 * @hidden
		 */
		format?: Set<TimeParts> | 'hour';
	}
